		// Go
		"go.mod": "gomod",
		"go.sum": "gosum",

		// Java
		"pom.xml": "maven",

		// Rust
		"Cargo.lock": "cargo",

		// .NET
		"packages.lock.json": "nuget",
		"packages.config":    "nuget",
	}

	// Simulate the current incomplete LibraryMap from models/library.go
	currentLibraryMap := map[string]string{
		"package-lock.json":    "node",
		"yarn.lock":            "node",
		"Gemfile.lock":         "ruby",
		"Cargo.lock":           "rust",
		"composer.lock":        "php",
		"requirements.txt":     "python",
